patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..43a6e02fae80 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2229,6 +2229,17 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return BitOp;
     }

+    // fshl(X, 0, Y) --> shl X, Y if Y is known to be < BitWidth
+    // fshl(X, undef, Y) --> shl X, Y if Y is known to be < BitWidth
+    Value *Op2 = II->getArgOperand(2);
+    if (match(Op1, m_ZeroInt()) || match(Op1, m_Undef())) {
+      // Check if the shift amount is known to be < BitWidth
+      ConstantRange Op2Range = computeConstantRangeIncludingKnownBits(
+          Op2, /*ForSigned=*/false, SQ.getWithInstruction(II));
+      if (Op2Range.getUnsignedMax().ult(BitWidth))
+        return BinaryOperator::CreateShl(Op0, Op2);
+    }
+
     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

